func ToString(x interface{}) string {
	switch y := x.(type) {

	case time.Time:
		return y.Format("A Monday")

	case string:
		return y

	case fmt.Stringer:
		return y.String()

	case error:
		return y.Error()

	}

	if v := reflect.ValueOf(x); v.Kind() == reflect.String {
		return v.String()
	}

	return fmt.Sprint(x)
}
